from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body (or person) into a single,
    fluent sentence.  The function tries to use a natural phrasing for each
    predicate and joins the resulting clauses with commas and a final “and”.
    """
    if not triples:
        return ""

    # Normalize all triples to ensure consistent formatting
    normalized_triples = []
    for t in triples:
        normalized_triples.append(Triple(
            subject=t.subject.strip(),
            predicate=t.predicate.strip(),
            object=t.object.strip()
        ))
    triples = normalized_triples

    # Normalize all triples to ensure consistent formatting
    normalized_triples = []
    for t in triples:
        normalized_triples.append(Triple(
            subject=t.subject.strip(),
            predicate=t.predicate.strip(),
            object=t.object.strip()
        ))
    triples = normalized_triples

    # Simple template mapping for common predicates
    def phrase(t: Triple) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object

        # Normalise predicate strings (remove spaces, lower‑case)
        p = pred.strip().lower()

        # Mapping of predicate to a readable clause
        if p == "discoverer":
            return f"{subj} was discovered by {obj}"
        if p == "discovered":
            return f"{subj} was discovered on {obj}"
        if p == "epoch":
            return f"with an epoch of {obj}"
        if p == "apoapsis":
            return f"has an apoapsis of {obj}"
        if p == "periapsis":
            return f"has a periapsis of {obj}"
        if p == "orbitalperiod":
            return f"with an orbital period of {obj}"
        if p == "averagespeed":
            return f"travels at an average speed of {obj}"
        if p == "escapevelocity":
            return f"has an escape velocity of {obj}"
        if p == "mass":
            return f"with a mass of {obj}"
        if p == "density":
            return f"with a density of {obj}"
        if p == "temperature":
            return f"with a temperature of {obj}"
        if p == "maximumtemperature":
            return f"with a maximum temperature of {obj}"
        if p == "meantemperature":
            return f"with a mean temperature of {obj}"
        if p == "minimumtemperature":
            return f"with a minimum temperature of {obj}"
        if p == "rotationperiod":
            return f"with a rotation period of {obj}"
        if p == "surfacearea":
            return f"with a surface area of {obj}"
        if p == "absolutemagnitude":
            return f"with an absolute magnitude of {obj}"
        if p == "formername":
            return f"formerly known as {obj}"
        if p == "birthdate":
            return f"born on {obj}"
        if p == "deathdate":
            return f"died on {obj}"
        if p == "birthplace":
            return f"born in {obj}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "deathcause":
            return f"died of {obj}"
        if p == "nationality" or p == "stateoforigin":
            return f"from {obj}"
        if p == "alnamater" or p == "alnamater":
            return f"studied at {obj}"
        if p == "almaMater" or p == "alnamater":
            return f"studied at {obj}"
        if p == "doctoralstudent":
            return f"supervised {obj}"
        # Fallback generic wording
        return f"{subj} {pred} {obj}"

    # Group triples by subject
    subject_groups = {}
    for t in triples:
        if t.subject not in subject_groups:
            subject_groups[t.subject] = []
        subject_groups[t.subject].append(t)

    # Build sentence parts
    parts = []
    subjects = list(subject_groups.keys())

    for i, subj in enumerate(subjects):
        subj_triples = subject_groups[subj]

        # First clause includes the subject name
        first_triple = subj_triples[0]
        first_p = first_triple.predicate.strip().lower()

        # Determine the opening clause based on first predicate
        if first_p == "discoverer":
            opening = f"{subj} was discovered by {first_triple.object}"
        elif first_p == "discovered":
            opening = f"{subj} was discovered on {first_triple.object}"
        else:
            opening = f"{subj} {phrase(first_triple).replace(subj + ' ', '')}"

        parts.append(opening)

        # Add remaining predicates for this subject as relative clauses
        for j in range(1, len(subj_triples)):
            t = subj_triples[j]
            p = t.predicate.strip().lower()
            clause = phrase(t)

            # Remove subject from clause and add appropriate connector
            if p in ["epoch", "orbitalperiod", "averagespeed", "escapevelocity",
                     "mass", "density", "temperature", "maximumtemperature",
                     "meantemperature", "minimumtemperature", "rotationperiod",
                     "surfacearea", "absolutemagnitude"]:
                clause = clause.replace(f"{subj} ", "")
                parts.append(f", which has {clause.replace('with ', '').replace('has ', '')}")
            elif p in ["was born", "died", "studied", "supervised", "formerly known as"]:
                clause = clause.replace(f"{subj} ", "")
                parts.append(f", {clause}")
            else:
                clause = clause.replace(f"{subj} ", "")
                parts.append(f", {clause}")

    # Join all parts and capitalize first character
    sentence = "".join(parts) + "."
    return sentence[0].upper() + sentence[1:]

